import { useContext, useEffect, useState } from "react"
import axios from 'axios'
import InitialListing from "../components/InitialListing"
import { UserContext } from "../context/UserContext"
const IndexPage =()=>{
    const [allItems ,setAllItems] = useState([])
const {user} = useContext(UserContext)
    useEffect(()=>{
        const fetchData =async()=>{
            try {
                const response = await axios.get('initial/items/all')
                if(user){
                    const newData = response.data.filter((item)=>item.owner!==user?.userId)
                    setAllItems(newData)          
                }else
                {
                    setAllItems(response.data)
                }
            } catch (error) {
                console.log(error)
            }
        }
        fetchData()
    },[user])

    return <div>
        <h1 className="">ALL LISTING </h1>
        <div className="mt-2 grid grid-cols-1 gap-6 md:grid-cols-2 lg:grid-cols-4">
            {
                allItems.map((item ,index)=>{
                    return (
                        <InitialListing props={item} key={index} />
                    )
                })
            }
        </div>
    </div>
}

export default IndexPage
